+/// Check if a SELECT's WHERE clause contains a self-referencing correlated
+/// EXISTS subquery (where the EXISTS subquery scans the same underlying table
+/// as the outer query, just with a different alias).
+fn select_has_correlated_exists_in_where(select: &SelectStatement) -> bool {
+    let SelectCore::Select {
+        where_clause,
+        from: Some(from),
+        ..
+    } = &select.body.select
+    else {
+        return false;
+    };
+    let outer_table = match &from.source {
+        TableOrSubquery::Table { name, .. } => &name.name,
+        _ => return false,
+    };
+    if let Some(wh) = where_clause {
+        return expr_has_self_referencing_correlated_exists(wh, outer_table);
+    }
+    false
+}
