+/// Return true if `expr` contains a correlated EXISTS subquery whose inner
+/// FROM table is the same underlying table as `outer_table` (self-join
+/// pattern). The VDBE emit_exists_subquery has a known issue with this
+/// pattern; non-self-referencing correlated EXISTS works correctly.
+fn expr_has_self_referencing_correlated_exists(expr: &Expr, outer_table: &str) -> bool {
+    match expr {
+        Expr::Exists { subquery, .. } => {
+            if !is_correlated_subquery(subquery) {
+                return false;
+            }
+            // Check if the EXISTS subquery's FROM table is the same as the outer table.
+            if let SelectCore::Select {
+                from: Some(from), ..
+            } = &subquery.body.select
+            {
+                if let TableOrSubquery::Table { name, .. } = &from.source {
+                    return name.name.eq_ignore_ascii_case(outer_table);
+                }
+            }
+            false
+        }
+        Expr::BinaryOp { left, right, .. } => {
+            expr_has_self_referencing_correlated_exists(left, outer_table)
+                || expr_has_self_referencing_correlated_exists(right, outer_table)
+        }
+        Expr::UnaryOp { expr: inner, .. }
+        | Expr::IsNull { expr: inner, .. }
+        | Expr::Cast { expr: inner, .. }
+        | Expr::Collate { expr: inner, .. } => {
+            expr_has_self_referencing_correlated_exists(inner, outer_table)
+        }
+        Expr::In { expr: inner, .. } => {
+            expr_has_self_referencing_correlated_exists(inner, outer_table)
+        }
+        _ => false,
+    }
+}
